import anthropic, json

client = anthropic.Anthropic()

TOOLS = [{
    "name": "calculator",
    "description": "Evaluate a Python arithmetic expression",
    "input_schema": {
        "type": "object",
        "properties": {"expr": {"type": "string"}},
        "required": ["expr"],
    },
}]

SYSTEM = (
    "Solve the problem step by step. Think before each action. "
    "Use the calculator for any arithmetic. When done, reply with 'ANSWER: <value>'."
)

def run(question: str, max_steps: int = 8) -> str:
    messages = [{"role": "user", "content": question}]
    for step in range(max_steps):
        resp = client.messages.create(
            model="claude-sonnet-4-5-20250929",
            max_tokens=1024,
            system=SYSTEM,
            tools=TOOLS,
            messages=messages,
        )
        if resp.stop_reason == "tool_use":
            results = []
            for block in resp.content:
                if block.type == "tool_use":
                    val = eval(block.input["expr"], {"__builtins__": {}})  # sandboxed
                    results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": str(val),
                    })
            messages += [
                {"role": "assistant", "content": resp.content},
                {"role": "user", "content": results},
            ]
        else:
            return "".join(b.text for b in resp.content if hasattr(b, "text"))
    return "step budget exhausted"

def solve_verified(problem, generate, verify, budget=16):
    """Generate up to `budget` reasoning trajectories; return the first that verifies."""
    best = None
    for i in range(budget):
        candidate = generate(problem, temperature=0.8)   # diverse sampling
        ok, detail = verify(candidate)                   # unit tests / checker
        if ok:
            return {"answer": candidate, "attempts": i + 1, "verified": True}
        best = candidate
    return {"answer": best, "attempts": budget, "verified": False}
